vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

float sunx =  q31*0.5 +0.55, suny = q32*0.5 + 0.34;
//if(sqrt(pow(vUv.x - q31*0.5 -0.55 ,2) + pow(vUv.y-q32*0.5 - 0.34,2))<0.05) {ret = 1;}
vec2 sunpos = vec2(0.5,0.5);
uva = (vUv-0.5)*uAspect.xy+0.5;
float sun = (.01 / length(uva-sunpos));

dz.x = lum(GetPixel(vUv-hor)) - lum(GetPixel(vUv+hor));
dz.y = lum(GetPixel(vUv-ver)) - lum(GetPixel(vUv+ver));

vec3 shine = GetPixel(vUv);

radi = 1;
for (int n=1; n <= anz; n++)
{
  shine += (1 + 2*q2)/anz*Get1((vUv-sunpos)*radi+sunpos,radi);
  radi -= 0.75/anz;;
}
ret += max(shine,0*GetPixel(vUv));
//ret = shine+GetPixel(vUv);
ret *= 0+audioLowSmooth/4;

  fragColor = ret;
}
